def solve(value: Array[Long], limit: Array[Long]): Long = {
  import scala.collection.mutable.PriorityQueue

  val n = value.length
  val pq = PriorityQueue[(Long, Int)]()(Ordering.by(-_._1))

  for (i <- 0 until n) {
    pq.add((value(i), i))
  }

  var activeCount = 0
  var totalSum = 0L
  val activated = Array.fill(n)(false)
  val inactive = Array.fill(n)(true)

  while (pq.nonEmpty) {
    val (valI, i) = pq.head
    if (inactive(i)) {
      if (activeCount < limit(i)) {
        // Activate this element
        totalSum += valI
        activated(i) = true
        inactive(i) = false
        activeCount += 1

        // Mark all elements j where limit[j] <= activeCount as inactive
        for (j <- 0 until n) {
          if (inactive(j) && limit(j) <= activeCount) {
            inactive(j) = true
          }
        }
      } else {
        // Cannot activate this element, remove it from the priority queue
        pq.remove(pq.head)
      }
    } else {
      // Element is already activated, remove it from the priority queue
      pq.remove(pq.head)
    }
  }

  totalSum
}
